// Parsea mensajes tipo (montos en COP):
//   gasto 25000 almuerzo
//   ingreso 2500000 sueldo
//   gasto 25k almuerzo  (k = mil)
//   gasto 1.5M arriendo (M = millón)
//
// Formato: <tipo> <monto> <descripcion...> [#categoria]

const tg = $json.message;
const text = String(tg.text || '').trim();
const parts = text.split(/\s+/);

const tipoRaw = parts[0]?.toLowerCase();
const tipo = ['gasto', 'gaste', 'gasté', 'pago', 'compra'].includes(tipoRaw)
  ? 'gasto'
  : ['ingreso', 'cobro', 'sueldo', 'cobré'].includes(tipoRaw)
  ? 'ingreso'
  : null;

if (!tipo) {
  return [{ json: { _ignore: true, _reason: 'comando inválido', _help: 'Usá: gasto 25000 almuerzo  |  ingreso 2500000 sueldo' } }];
}

// Parsear monto con sufijos colombianos: 25k = 25000, 1.5M = 1500000
function parseMonto(raw) {
  if (!raw) return NaN;
  const m = String(raw).toLowerCase().replace(/[\.,]/g, (c, i, s) => {
    // Mantener punto solo si es decimal (1.5M); quitar separadores de miles
    return c === '.' && /\d/.test(s[i + 1] || '') ? '.' : '';
  });
  const match = m.match(/^([0-9]*\.?[0-9]+)\s*([km]?)$/);
  if (!match) return Number(raw);
  const n = parseFloat(match[1]);
  if (match[2] === 'k') return n * 1000;
  if (match[2] === 'm') return n * 1000000;
  return n;
}

const monto = parseMonto(parts[1]);
if (!Number.isFinite(monto) || monto <= 0) {
  return [{ json: { _ignore: true, _reason: 'monto inválido' } }];
}

// El resto es descripción; si hay palabra con # → categoría
let descripcion = parts.slice(2).join(' ');
let categoria = 'otros';
const hash = descripcion.match(/#(\w+)/);
if (hash) {
  categoria = hash[1].toLowerCase();
  descripcion = descripcion.replace(/#\w+/, '').trim();
} else {
  // Heurística simple por keywords (contexto Colombia)
  const map = {
    comida: ['almuerzo', 'cena', 'desayuno', 'pizza', 'restaurante', 'mercado', 'tinto', 'corrientazo'],
    transporte: ['uber', 'didi', 'taxi', 'bus', 'gasolina', 'transmilenio', 'metro', 'sitp'],
    ocio: ['cine', 'fiesta', 'salida', 'bar', 'rumba'],
    salud: ['farmacia', 'medicina', 'doctor', 'eps'],
    hogar: ['arriendo', 'alquiler', 'luz', 'agua', 'internet', 'gas', 'administracion'],
    sueldo: ['sueldo', 'salario', 'nomina', 'nómina', 'quincena'],
    freelance: ['freelance', 'cliente', 'proyecto', 'factura'],
  };
  for (const [cat, keys] of Object.entries(map)) {
    if (keys.some(k => descripcion.toLowerCase().includes(k))) { categoria = cat; break; }
  }
}

return [{
  json: {
    tipo,
    monto: Math.round(monto),
    categoria,
    descripcion: descripcion || tipo,
    usuario: tg.from?.username ? '@' + tg.from.username : tg.from?.first_name,
    raw_text: tg.text,
  }
}];
